mapper.insert:
INSERT INTO coupon_target (
    target_id, coupon_id, target_type, target_value, is_exclude
) VALUES (
    coupon_target_seq.NEXTVAL,
    #{couponId},
    #{targetType},
    #{targetValue},
    #{isExclude}
)

mapper.select:
SELECT r.room_id AS roomId, r.place_id AS placeId, r.room_name AS roomName, p.place_name AS placeName FROM room r JOIN place p ON r.place_id = p.place_id WHERE r.place_id = #{placeId}
AND r.room_name LIKE '%' || #{keyword} || '%'
ORDER BY r.room_name
